/*
  Course: INT-499 Capstone in Information Technology
  Instructor: John Russel
  Joshua Coman
*/

import React from "react";
import { NavLink } from "react-router-dom";
import { FaHome, FaStar, FaCog, FaSearch } from "react-icons/fa";
import './Navbar.css';

export default function Navbar() {
  return (
    <nav className="navbar">
      {/* Logo */}
      <div className="navbar-logo">StreamList</div>

      {/* Links */}
      <div className="navbar-links">
        <NavLink to="/"><FaHome /> Home</NavLink>
        <NavLink to="/favorites"><FaStar /> Favorites</NavLink>
        <NavLink to="/settings"><FaCog /> Settings</NavLink>

        {/* Search */}
        <div className="navbar-search">
          <input type="text" placeholder="Search..." />
          <FaSearch />
        </div>
      </div>
    </nav>
  );
}
